import re
from pathlib import Path

import pytest

AC_UID = "aa2a911022c763f1"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
TARGET_SCRIPTS = [
    REPO_ROOT / "scripts" / "score-update.sh",
    REPO_ROOT / "scripts" / "score-inject.sh",
    REPO_ROOT / "scripts" / "canary-verify.sh",
]

# Canonical subshell-wrap regex from acceptance-criteria-20260520-221452.json#/items/9 (AC-10)
CANONICAL_RE = re.compile(
    r"\(\s*source\s+(?:~|\$\{?HOME\}?|/root)/\.claude/venv/bin/activate\s*&&\s*python3\b"
)
PYTHON3_TOKEN_RE = re.compile(r"\bpython3\b")


def _strip_comment(line: str) -> str:
    """Strip from first unquoted '#'."""
    out = []
    in_s = False
    in_d = False
    i = 0
    while i < len(line):
        c = line[i]
        if c == "\\" and i + 1 < len(line):
            out.append(c)
            out.append(line[i + 1])
            i += 2
            continue
        if c == "'" and not in_d:
            in_s = not in_s
        elif c == '"' and not in_s:
            in_d = not in_d
        elif c == "#" and not in_s and not in_d:
            break
        out.append(c)
        i += 1
    return "".join(out)


def _mask_quoted(line: str) -> str:
    """Replace contents inside matching single/double quotes with empty placeholder."""
    out = []
    in_s = False
    in_d = False
    i = 0
    while i < len(line):
        c = line[i]
        if c == "\\" and i + 1 < len(line):
            if not (in_s or in_d):
                out.append(c)
                out.append(line[i + 1])
            i += 2
            continue
        if c == "'" and not in_d:
            if in_s:
                in_s = False
            else:
                in_s = True
            out.append("'")
        elif c == '"' and not in_s:
            if in_d:
                in_d = False
            else:
                in_d = True
            out.append('"')
        else:
            if in_s or in_d:
                pass  # mask
            else:
                out.append(c)
            i += 1
            continue
        i += 1
    return "".join(out)


def test_AC_10():
    """
    GIVEN: scripts/score-update.sh, scripts/score-inject.sh, scripts/canary-verify.sh are read as text with shell-comment stripping AND quoted-string masking applied before regex matching
    WHEN:  for each non-comment, non-string-literal line in each file that contains the literal token `python3` as a shell word, the same line is matched against the canonical subshell-wrap regex
    THEN:  every actual `python3` invocation site (after comment stripping AND quoted-string masking) is inside a same-line subshell `( source ~/.claude/venv/bin/activate && python3 ... )`. Quoted strings or inline comments containing the word 'python3' do NOT count as invocation sites.
    """
    violations = []
    for script in TARGET_SCRIPTS:
        assert script.is_file(), f"missing target script: {script}"
        raw_lines = script.read_text(encoding="utf-8").splitlines()
        for lineno, raw_line in enumerate(raw_lines, start=1):
            stripped = _strip_comment(raw_line)
            masked = _mask_quoted(stripped)
            if not PYTHON3_TOKEN_RE.search(masked):
                continue
            # invocation site detected — original line must match canonical subshell wrap
            if not CANONICAL_RE.search(raw_line):
                violations.append((str(script), lineno, raw_line.rstrip()))
    assert not violations, (
        "python3 invocation sites not wrapped in canonical subshell:\n"
        + "\n".join(f"  {f}:{ln}: {body}" for f, ln, body in violations)
    )
